async function updateOrderInDynamoDB(orderId, updateAttributes) {
    console.log(`Updating DynamoDB for Order ID: ${orderId} with:`, updateAttributes);
    try {
        const params = {
            TableName: DYNAMODB_TABLE_NAME,
            Key: { orderId: orderId }, // Assuming 'orderId' is the primary key
            UpdateExpression: "SET " + Object.keys(updateAttributes).map(key => `#${key} = :${key}`).join(", "),
            ExpressionAttributeNames: Object.keys(updateAttributes).reduce((acc, key) => ({ ...acc, [`#${key}`]: key }), {}),
            ExpressionAttributeValues: Object.keys(updateAttributes).reduce((acc, key) => ({ ...acc, [`:${key}`]: updateAttributes[key] }), {}),
            ReturnValues: "UPDATED_NEW",
        };

        const command = new UpdateCommand(params);
        await documentClient.send(command);
        console.log(`DynamoDB updated successfully for Order ID: ${orderId}`);
    } catch (error) {
        console.error(`Error updating DynamoDB for Order ID ${orderId}:`, error);
        throw error;
    }
}

export const handler = async (event) => {
    const processingPromises = event.Records.map(async (record) => {
        let order;
        let orderId = 'unknown'; // Default for logging if parsing fails early

        try {
            order = JSON.parse(record.body);
            orderId = order.orderId; // Get orderId as soon as possible

            const { amount, currency } = order;

            if (!orderId || !amount || !currency) {
                const errorMessage = `Invalid order structure for record body: ${record.body}. Missing orderId, amount, or currency.`;
                console.error(errorMessage);
                return { status: 'failed', orderId: orderId || 'unknown', reason: 'Invalid order data' };
            }
            console.log(`Processing order: ${orderId}`);

            // 1. Call External Payment API
            let paymentResult;
            try {
                paymentResult = await callPaymentApi(orderId, amount, currency);
            } catch (paymentError) {
                console.error(`Failed to process payment for Order ID ${orderId}:`, paymentError);
                // Attempt to update DB with payment failure status. Log if this update also fails.
                await updateOrderInDynamoDB(orderId, { paymentStatus: 'FAILED', paymentError: paymentError.message, lastUpdated: new Date().toISOString() })
                    .catch(dbError => console.error(`Failed to update DB with payment error status for ${orderId}:`, dbError));
                return { status: 'failed', orderId, reason: 'Payment API failure' };
            }

            // 2. Update DynamoDB with payment status
            const dbUpdateAttributes = {
                paymentStatus: paymentResult.status,
                transactionId: paymentResult.transactionId,
                lastUpdated: new Date().toISOString()
            };

            try {
                await updateOrderInDynamoDB(orderId, dbUpdateAttributes);
                console.log(`Successfully processed Order ID: ${orderId}`);
                return { status: 'success', orderId };
            } catch (dbUpdateError) {
                console.error(`Failed to update DynamoDB for Order ID ${orderId} after successful payment:`, dbUpdateError);
                // Payment succeeded, but DB update failed. This needs monitoring.
                return { status: 'failed', orderId, reason: 'DynamoDB update failure after successful payment' };
            }

        } catch (parseError) {
            console.error(`Error parsing SQS record body: ${record.body}`, parseError);
            return { status: 'failed', orderId: orderId, reason: 'Message parsing failure' };
        }
    });

    // Process all orders concurrently using Promise.allSettled.
    // This ensures all promises complete, regardless of individual success or failure,
    // allowing the Lambda to process the entire SQS batch without stopping on the first error.
    const results = await Promise.allSettled(processingPromises);

    results.forEach((result, index) => {
        if (result.status === 'fulfilled') {
            console.log(`Record ${index} processing outcome:`, result.value);
        } else {
            // This captures any unhandled rejections from within processingPromises,
            // though most errors should be caught and converted to 'failed' status objects.
            console.error(`Record ${index} processing failed unexpectedly with rejection:`, result.reason);
        }
    });

    // The Lambda function itself returns a 200 OK response to SQS.
    // This instructs SQS to delete all messages from the batch, even if some individual messages
    // failed processing internally. Errors are logged to CloudWatch for monitoring.
    return {
        statusCode: 200,
        body: JSON.stringify({ message: 'Batch processing complete. Check CloudWatch logs for details on each order.' }),
    };
};